// Extract topic and content type from request
const body = $input.first().json;

const topic = body.topic || 'AI automation trends';
const contentType = body.type || 'blog'; // 'blog', 'newsletter', 'social'
const language = body.language || 'English';
const tone = body.tone || 'professional but approachable';

const prompts = {
  blog: `Write a complete blog post about: "${topic}"

Requirements:
- Title (H1)
- Introduction (2-3 sentences)
- 3 main sections with H2 headers
- Practical examples in each section
- Conclusion with call to action
- Tone: ${tone}
- Language: ${language}
- Length: ~600 words`,

  newsletter: `Write a newsletter issue about: "${topic}"

Requirements:
- Catchy subject line
- Opening hook (1-2 sentences)
- 3 key insights with brief explanations
- One actionable tip
- Sign-off
- Tone: ${tone}
- Language: ${language}
- Length: ~300 words`,

  social: `Write 3 social media posts about: "${topic}"

For each post:
- Platform variant (Twitter/X, LinkedIn, Instagram)
- Different angle for each
- Relevant hashtags
- Tone: ${tone}
- Language: ${language}`
};

return [{
  json: {
    topic,
    contentType,
    language,
    prompt: prompts[contentType] || prompts.blog
  }
}];

